for (uint256 i = 0; i < arrayLength; ++i) {
    if (_inputData.amounts[i] == type(uint256).max) {
        _inputData.amounts[i] = _inputData.tokens[i].getBalance(address(this));
    }
    // unwrap and send eth if token is weth
    if (_inputData.tokens[i] == TokenUtils.WETH_ADDR) {
        TokenUtils.withdrawWeth(_inputData.amounts[i]);
        _inputData.tokens[i] = TokenUtils.ETH_ADDR;
    }
    _inputData.tokens[i].withdrawTokens(_inputData.receivers[i], _inputData.amounts[i]);
}

if (inputInBEFormat_) {
    return
        abi.encodePacked(
            headerData_.version.uint32BEtoLE(),
            headerData_.prevBlockHash.bytes32BEtoLE(),
            headerData_.merkleRoot.bytes32BEtoLE(),
            headerData_.time.uint32BEtoLE(),
            (uint32(headerData_.bits)).uint32BEtoLE(),
            headerData_.nonce.uint32BEtoLE()
        );
}

if (includeWitness_) {
    for (uint256 i = 0; i < txInputsLength_; ++i) {
        uint256 witnessesLength_ = tx_.inputs[i].witnesses.length;
        result_ = abi.encodePacked(result_, formatCuint(uint64(witnessesLength_)));

        for (uint256 j = 0; j < witnessesLength_; ++j) {
            result_ = abi.encodePacked(
                result_,
                formatCuint(uint64(tx_.inputs[i].witnesses[j].length)),
                tx_.inputs[i].witnesses[j]
            );
        }
    }
}

unchecked {
    PPoint[16] memory pPoints_ = _preComputeProjectivePoints(ec, pPoint_);

    for (uint256 i = 0; i < 64; ++i) {
        pPoint2_ = pDoublePoint(ec, pPoint2_);
        pPoint2_ = pDoublePoint(ec, pPoint2_);
        pPoint2_ = pDoublePoint(ec, pPoint2_);
        pPoint2_ = pDoublePoint(ec, pPoint2_);

        // Read 4 bits of u1 which corresponds to the lookup index in the table.
        uint256 pos_ = scalar_ >> 252;
        scalar_ <<= 4;

        pPoint2_ = pAddPoint(ec, pPoints_[pos_], pPoint2_);
    }
}

unchecked {
    PPoint[16] memory pPoints_ = _preComputeProjectivePoints2(ec, pPoint1_, pPoint2_);

    for (uint256 i = 0; i < 128; ++i) {
        pPoint3_ = pDoublePoint(ec, pPoint3_);
        pPoint3_ = pDoublePoint(ec, pPoint3_);

        // Read 2 bits of u1, and 2 bits of u2. Combining the two gives the lookup index in the table.
        uint256 pos_ = ((scalar1_ >> 252) & 0xc) | ((scalar2_ >> 254) & 0x3);
        scalar1_ <<= 2;
        scalar2_ <<= 2;

        pPoint3_ = pAddPoint(ec, pPoints_[pos_], pPoint3_);
    }
}

if (rootNode.key > key_) {
    rootNode.childLeft = uint64(_add(treaple, rootNode.childLeft, key_));

    if (treaple.nodes[rootNode.childLeft].priority > rootNode.priority) {
        rootNodeId_ = _rightRotate(treaple, rootNodeId_);
        rootNode = treaple.nodes[uint64(rootNodeId_)];
    }
} else {
    rootNode.childRight = uint64(_add(treaple, rootNode.childRight, key_));

    if (treaple.nodes[rootNode.childRight].priority > rootNode.priority) {
        rootNodeId_ = _leftRotate(treaple, rootNodeId_);
        rootNode = treaple.nodes[uint64(rootNodeId_)];
    }
}

